+            b"PERSIST",
+            b"set",
+            b"get",
+            b"DeL",
+            b"UNKNOWN",
+            b"host:",
+            &[0xFF, 0xFE],
+            &[0xC3, 0x91, b'X'],
+        ];
+
+        for sample in samples {
+            let optimized = classify_command(sample);
+            let linear = classify_packet_008_dispatch_linear(sample);
